   449→
   450→interface SubtypeDefinition {
   451→  description: string;
   452→  rule_based_classification?: {
   453→    high_confidence?: RulePattern[];
   454→    medium_confidence?: RulePattern[];
   455→    low_confidence?: RulePattern[];
