   172→export async function fetchEmailsByDateRange(
   173→  startDate: Date,
   174→  endDate: Date,
   175→  limit: number = 100
   176→): Promise<EmailMessage[]> {
   177→  // Validate date range
   178→  if (startDate > endDate) {
   179→    throw new Error('Invalid date range: start date must be before end date');
   180→  }
   181→
   182→  const pool = getPool();
   183→
   184→  const query = `
   185→    SELECT
   186→      gm.gmail_id,
   187→      gm.gmail_thread_id,
   188→      gm.label_ids,
   189→      gm.subject,
   190→      gm.sent_at,
   191→      gm.message_id_hdr,
   192→      gm.from_simple,
   193→      gm.to_addrs,
   194→      gm.reply_to_addrs,
   195→      gm.headers,
   196→      gm.body_text,
   197→      gm.body_html,
   198→      gm.raw,
   199→      gm.size_estimate,
   200→      cs.session_id,
   201→      cs.completed_at
   202→    FROM email.gmail_message gm
   203→    LEFT JOIN LATERAL (
   204→      SELECT session_id, completed_at
   205→      FROM email.classification_session
   206→      WHERE gmail_id = gm.gmail_id
   207→      ORDER BY started_at DESC
   208→      LIMIT 1
   209→    ) cs ON true
   210→    WHERE gm.sent_at >= $1 AND gm.sent_at <= $2
   211→    ORDER BY gm.sent_at DESC
   212→    LIMIT $3
   213→  `;
