   402→function encodeCursor(cursor: Cursor): string {
   403→  const json = JSON.stringify(cursor);
   404→  return Buffer.from(json).toString('base64');
   405→}
   406→
   407→/**
   408→ * Decode cursor for pagination
   409→ */
   410→function decodeCursor(cursorStr: string): Cursor {
   411→  try {
   412→    const json = Buffer.from(cursorStr, 'base64').toString('utf-8');
   413→    const cursor = JSON.parse(json) as Cursor;
   414→
   415→    // Validate cursor structure
   416→    if (!cursor.timestamp || !cursor.id) {
   417→      throw new Error('Invalid cursor structure');
   418→    }
   419→
   420→    // Validate timestamp format
   421→    if (isNaN(new Date(cursor.timestamp).getTime())) {
   422→      throw new Error('Invalid cursor timestamp');
   423→    }
   424→
   425→    return cursor;
   426→  } catch (error) {
   427→    throw new Error(`Invalid cursor format: ${(error as Error).message}`);
   428→  }
   429→}
   430→
   431→/**
   432→ * Build WHERE clause from criteria
   433→ */
   434→function buildWhereClause(
   435→  criteria: EmailQueryCriteria,
   436→  paramOffset: number = 0
   437→): { clause: string; params: unknown[] } {
   438→  const conditions: string[] = [];
   439→  const params: unknown[] = [];
   440→  let paramIndex = paramOffset + 1;
   441→
   442→  // Subject filter
   443→  if (criteria.subject) {
   444→    conditions.push(`gm.subject ILIKE $${paramIndex}`);
   445→    params.push(`%${criteria.subject}%`);
   446→    paramIndex++;
   447→  }
   448→
   449→  // From filter
   450→  if (criteria.from) {
   451→    conditions.push(`(gm.from_simple::text ILIKE $${paramIndex})`);
   452→    params.push(`%${criteria.from}%`);
   453→    paramIndex++;
   454→  }
   455→
   456→  // Body contains filter
   457→  if (criteria.bodyContains) {
   458→    conditions.push(`(gm.body_text ILIKE $${paramIndex} OR gm.body_html ILIKE $${paramIndex})`);
   459→    params.push(`%${criteria.bodyContains}%`);
   460→    paramIndex++;
   461→  }
   462→
   463→  // Date range filter
   464→  if (criteria.dateRange) {
   465→    conditions.push(`gm.sent_at >= $${paramIndex}`);
   466→    params.push(criteria.dateRange.start);
   467→    paramIndex++;
   468→
   469→    conditions.push(`gm.sent_at <= $${paramIndex}`);
   470→    params.push(criteria.dateRange.end);
   471→    paramIndex++;
   472→  }
   473→
   474→  // Gmail labels filter (OR logic)
   475→  if (criteria.gmailLabels && criteria.gmailLabels.length > 0) {
   476→    conditions.push(`gm.label_ids && $${paramIndex}::text[]`);
   477→    params.push(criteria.gmailLabels);
   478→    paramIndex++;
   479→  }
   480→
   481→  // Processing status filter
   482→  if (criteria.isProcessed !== undefined) {
   483→    if (criteria.isProcessed) {
   484→      conditions.push('cs.session_id IS NOT NULL');
   485→    } else {
   486→      conditions.push('cs.session_id IS NULL');
   487→    }
   488→  }
   489→
   490→  // Primary category filter (requires JOIN with session_category)
   491→  if (criteria.primaryCategory) {
   492→    conditions.push(`sc.category_code = $${paramIndex}`);
   493→    params.push(criteria.primaryCategory);
   494→    paramIndex++;
   495→    conditions.push('sc.label_type = 0'); // 0 = PRIMARY
   496→  }
   497→
   498→  // Minimum confidence filter (requires JOIN with classification_session)
   499→  if (criteria.minConfidence !== undefined) {
   500→    conditions.push(`cs.confidence >= $${paramIndex}`);
   501→    params.push(criteria.minConfidence);
   502→    paramIndex++;
   503→  }
   504→
   505→  // Urgency filter (requires JOIN with detected_attribute)
   506→  if (criteria.urgency) {
   507→    conditions.push(`da.attribute_name = 'urgency'`);
   508→    conditions.push(`da.attribute_value = $${paramIndex}`);
   509→    params.push(criteria.urgency);
   510→    paramIndex++;
   511→  }
   512→
   513→  const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
   514→  return { clause: whereClause, params };
   515→}
   516→
   517→/**
   518→ * Build FROM clause with necessary JOINs based on criteria
   519→ */
   520→function buildFromClause(criteria: EmailQueryCriteria, pagination?: PaginationOptions): string {
   521→  let fromClause = 'FROM email.gmail_message gm';
   522→
   523→  // Always LEFT JOIN classification_session for processing status
   524→  fromClause += `
   525→    LEFT JOIN LATERAL (
   526→      SELECT session_id, completed_at, confidence
   527→      FROM email.classification_session
   528→      WHERE gmail_id = gm.gmail_id
   529→      ORDER BY started_at DESC
   530→      LIMIT 1
   531→    ) cs ON true`;
   532→
   533→  // JOIN session_category if filtering by category
   534→  if (criteria.primaryCategory) {
   535→    fromClause += `
   536→    LEFT JOIN email.session_category sc ON cs.session_id = sc.session_id`;
   537→  }
   538→
   539→  // JOIN detected_attribute if filtering by urgency
   540→  if (criteria.urgency) {
   541→    fromClause += `
   542→    LEFT JOIN email.detected_attribute da ON cs.session_id = da.session_id`;
   543→  }
   544→
   545→  // JOIN for confidence-based sorting
   546→  if (pagination?.sortBy === 'confidence') {
   547→    // Already have cs.confidence from classification_session JOIN
   548→  }
   549→
   550→  return fromClause;
   551→}
   552→
   553→/**
   554→ * Build ORDER BY clause
   555→ */
   556→function buildOrderByClause(pagination?: PaginationOptions): string {
   557→  const sortBy = pagination?.sortBy || 'date';
   558→  const sortOrder = pagination?.sortOrder || 'desc';
   559→
   560→  if (sortBy === 'confidence') {
   561→    return `ORDER BY cs.confidence ${sortOrder.toUpperCase()}, gm.sent_at DESC`;
   562→  }
   563→
   564→  // Default: sort by date
   565→  return `ORDER BY gm.sent_at ${sortOrder.toUpperCase()}`;
   566→}
   567→
   568→/**
   569→ * Validate criteria and pagination options
   570→ */
   571→function validateCriteriaAndPagination(criteria: EmailQueryCriteria, pagination?: PaginationOptions): void {
   572→  // Validate date range
   573→  if (criteria.dateRange) {
   574→    if (criteria.dateRange.start > criteria.dateRange.end) {
   575→      throw new Error('Invalid date range: start date must be before end date');
   576→    }
   577→  }
   578→
   579→  // Validate confidence range
   580→  if (criteria.minConfidence !== undefined) {
   581→    if (criteria.minConfidence < 0 || criteria.minConfidence > 1) {
   582→      throw new Error('Invalid confidence: must be between 0.0 and 1.0');
   583→    }
   584→  }
   585→
   586→  // Validate pagination limit
   587→  if (pagination?.limit !== undefined) {
   588→    if (pagination.limit < 0) {
   589→      throw new Error('Invalid limit: must be non-negative');
   590→    }
   591→    if (pagination.limit > 1000) {
   592→      throw new Error('Limit exceeds maximum allowed value of 1000');
   593→    }
   594→  }
   595→}
   596→
   597→/**
   598→ * Fetch emails with criteria-based selection and pagination (T048)
   599→ *
   600→ * @param criteria - Query criteria for filtering
   601→ * @param pagination - Pagination options (limit, cursor, sort)
   602→ * @returns Paginated result with email messages
   603→ */
   604→export async function fetchEmailsByCriteria(
   605→  criteria: EmailQueryCriteria,
   606→  pagination?: PaginationOptions
   607→): Promise<PaginatedResult<EmailMessage>> {
   608→  // Validate inputs
   609→  validateCriteriaAndPagination(criteria, pagination);
   610→
   611→  const pool = getPool();
   612→
   613→  // Pagination defaults
   614→  const limit = pagination?.limit || 50;
   615→  const includeTotalCount = pagination?.includeTotalCount || false;
   616→
   617→  // Decode cursor if provided
   618→  let cursorData: Cursor | null = null;
   619→  if (pagination?.cursor) {
   620→    cursorData = decodeCursor(pagination.cursor);
   621→  }
   622→
   623→  // Build query components
   624→  const { clause: whereClause, params } = buildWhereClause(criteria);
   625→  const fromClause = buildFromClause(criteria, pagination);
   626→  const orderByClause = buildOrderByClause(pagination);
   627→
   628→  // Add cursor conditions to WHERE clause
   629→  let cursorCondition = '';
   630→  let cursorParams: unknown[] = [];
   631→  if (cursorData) {
   632→    const cursorParamIndex = params.length + 1;
   633→    const sortOrder = pagination?.sortOrder || 'desc';
   634→
   635→    if (sortOrder === 'desc') {
   636→      cursorCondition = `AND (gm.sent_at < $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id < $${cursorParamIndex + 1}))`;
   637→    } else {
   638→      cursorCondition = `AND (gm.sent_at > $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id > $${cursorParamIndex + 1}))`;
   639→    }
   640→    cursorParams = [cursorData.timestamp, cursorData.id];
   641→  }
   642→
   643→  // Construct main query (fetch limit + 1 to determine hasMore)
   644→  const query = `
   645→    SELECT
   646→      gm.gmail_id,
   647→      gm.gmail_thread_id,
   648→      gm.label_ids,
   649→      gm.subject,
   650→      gm.sent_at,
   651→      gm.message_id_hdr,
   652→      gm.from_simple,
   653→      gm.to_addrs,
   654→      gm.reply_to_addrs,
   655→      gm.headers,
   656→      gm.body_text,
   657→      gm.body_html,
   658→      gm.raw,
   659→      gm.size_estimate,
   660→      cs.session_id,
   661→      cs.completed_at
   662→    ${fromClause}
   663→    ${whereClause} ${cursorCondition}
   664→    ${orderByClause}
   665→    LIMIT $${params.length + cursorParams.length + 1}
   666→  `;
   667→
   668→  const queryParams = [...params, ...cursorParams, limit + 1];
   669→
   670→  try {
   671→    // Execute main query
   672→    const result = await pool.query(query, queryParams);
