+  // Pagination defaults
+  const limit = pagination?.limit || 50;
+  const includeTotalCount = pagination?.includeTotalCount || false;
+
+  // Decode cursor if provided
+  let cursorData: Cursor | null = null;
+  if (pagination?.cursor) {
+    cursorData = decodeCursor(pagination.cursor);
+  }
+
+  // Build query components
+  const { clause: whereClause, params } = buildWhereClause(criteria);
+  const fromClause = buildFromClause(criteria, pagination);
+  const orderByClause = buildOrderByClause(pagination);
+
+  // Add cursor conditions to WHERE clause
+  let cursorCondition = '';
+  let cursorParams: unknown[] = [];
+  if (cursorData) {
+    const cursorParamIndex = params.length + 1;
+    const sortOrder = pagination?.sortOrder || 'desc';
+
+    if (sortOrder === 'desc') {
+      cursorCondition = `AND (gm.sent_at < $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id < $${cursorParamIndex + 1}))`;
+    } else {
+      cursorCondition = `AND (gm.sent_at > $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id > $${cursorParamIndex + 1}))`;
+    }
+    cursorParams = [cursorData.timestamp, cursorData.id];
+  }
+
+  // Construct main query (fetch limit + 1 to determine hasMore)
+  const query = `
+    SELECT
+      gm.gmail_id,
+      gm.gmail_thread_id,
+      gm.label_ids,
+      gm.subject,
+      gm.sent_at,
+      gm.message_id_hdr,
+      gm.from_simple,
+      gm.to_addrs,
+      gm.reply_to_addrs,
+      gm.headers,
+      gm.body_text,
+      gm.body_html,
+      gm.raw,
+      gm.size_estimate,
+      cs.session_id,
+      cs.completed_at
+    ${fromClause}
+    ${whereClause} ${cursorCondition}
+    ${orderByClause}
+    LIMIT $${params.length + cursorParams.length + 1}
+  `;
+
+  const queryParams = [...params, ...cursorParams, limit + 1];
+
+  try {
+    // Execute main query
+    const result = await pool.query(query, queryParams);
+
+    // Determine hasMore and prepare items
+    const hasMore = result.rows.length > limit;
+    const items = result.rows.slice(0, limit).map(mapRowToEmailMessage);
+
+    // Generate nextCursor if hasMore
+    let nextCursor: string | undefined;
+    if (hasMore && items.length > 0) {
+      const lastItem = items[items.length - 1];
+      nextCursor = encodeCursor({
+        timestamp: lastItem.date.toISOString(),
+        id: lastItem.id,
+      });
+    }
+
+    // Fetch total count if requested (separate query for performance)
+    let totalCount: number | undefined;
+    if (includeTotalCount) {
+      const countQuery = `
+        SELECT COUNT(*) as count
+        ${fromClause}
+        ${whereClause}
+      `;
+
+      const countResult = await pool.query(countQuery, params);
+      totalCount = parseInt(countResult.rows[0].count, 10);
+    }
+
+    return {
+      items,
+      pagination: {
+        limit,
+        hasMore,
+        nextCursor,
+        totalCount,
+      },
+    };
+  } catch (error) {
+    throw new Error(`Failed to fetch emails by criteria: ${(error as Error).message}`);
+  }
+}
