/**
 * Database utility functions
 *
 * Simple helpers for working with pg.Pool directly.
 * Uses existing, proven pg library instead of custom abstractions.
 */

import { Pool, PoolClient, PoolConfig } from 'pg';

/**
 * Create a database connection pool with environment-based configuration
 *
 * @param overrides - Optional configuration overrides
 * @returns Configured Pool instance
 *
 * @example
 * ```typescript
 * const pool = createPool();
 * const result = await pool.query('SELECT * FROM users WHERE id = $1', [userId]);
 * await pool.end();
 * ```
 */
export function createPool(overrides?: PoolConfig): Pool {
  return new Pool({
    host: process.env.PROJECT_DB_HOST || 'localhost',
    port: parseInt(process.env.PROJECT_DB_PORT || '5432', 10),
    database: process.env.PROJECT_DB_NAME,
    user: process.env.PROJECT_DB_USER,
    password: process.env.PROJECT_DB_PASS,
    max: 10,
    idleTimeoutMillis: 10000,
    connectionTimeoutMillis: 3000,
    ...overrides,
  });
}

/**
 * Execute a function within a database transaction
 *
 * Automatically handles BEGIN/COMMIT/ROLLBACK and client cleanup.
 *
 * @param pool - Database connection pool
 * @param callback - Transaction callback receiving a client
 * @returns Transaction result
 *
 * @example
 * ```typescript
 * const pool = createPool();
 * const result = await withTransaction(pool, async (client) => {
 *   await client.query('INSERT INTO users (name) VALUES ($1)', ['Alice']);
 *   const result = await client.query('SELECT * FROM users WHERE name = $1', ['Alice']);
 *   return result.rows[0];
 * });
 * ```
 */
export async function withTransaction<T>(pool: Pool, callback: (client: PoolClient) => Promise<T>): Promise<T> {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const result = await callback(client);
    await client.query('COMMIT');
    return result;
  } catch (error) {
    await client.query('ROLLBACK');
    throw error;
  } finally {
    client.release();
  }
}

