import crypto from 'crypto';

const CURSOR_SECRET = process.env.CURSOR_SECRET || 'change-me-in-production';

function encodeCursor(cursor: Cursor): string {
  const json = JSON.stringify(cursor);
  const hmac = crypto
    .createHmac('sha256', CURSOR_SECRET)
    .update(json)
    .digest('hex')
    .substring(0, 16); // First 16 chars

  const payload = `${json}.${hmac}`;
  return Buffer.from(payload).toString('base64');
}

function decodeCursor(cursorStr: string): Cursor {
  try {
    const payload = Buffer.from(cursorStr, 'base64').toString('utf-8');
    const [json, receivedHmac] = payload.split('.');

    if (!json || !receivedHmac) {
      throw new Error('Invalid cursor structure');
    }

    // Verify HMAC
    const expectedHmac = crypto
      .createHmac('sha256', CURSOR_SECRET)
      .update(json)
      .digest('hex')
      .substring(0, 16);

    if (receivedHmac !== expectedHmac) {
      throw new Error('Cursor tampered with');
    }

    const cursor = JSON.parse(json) as Cursor;
    // ... existing validation ...
    return cursor;
  } catch (error) {
    throw new Error(`Invalid cursor format: ${(error as Error).message}`);
  }
}
```

