import { createPool } from '../database/db-utils';
import * as fs from 'fs';
import * as dotenv from 'dotenv';
import * as path from 'path';

// ========== Criteria-Based Query Types ==========

/**
 * Email query criteria for flexible filtering
 */
export interface EmailQueryCriteria {
  // Text-based filters
  subject?: string; // Case-insensitive substring match
  from?: string; // Case-insensitive substring match on email address
  bodyContains?: string; // Case-insensitive search in body_text or body_html

  // Date range filter
  dateRange?: {
    start: Date;
    end: Date;
  };

  // Gmail label filters (OR logic - matches any label)
  gmailLabels?: string[];

  // Processing status
  isProcessed?: boolean;

  // Classification filters (require JOIN with classification tables)
  primaryCategory?: string; // Filter by primary category
  minConfidence?: number; // Minimum classification confidence (0.0 - 1.0)
  urgency?: 'low' | 'medium' | 'high'; // Filter by urgency attribute
}

/**
 * Pagination options for query results
 */
export interface PaginationOptions {
  // Limit number of results (default: 50, max: 1000)
  limit?: number;

  // Cursor for pagination (opaque string: base64-encoded timestamp+id)
  cursor?: string;

  // Sort options
  sortBy?: 'date' | 'confidence';
  sortOrder?: 'asc' | 'desc';

  // Include total count in response (requires separate COUNT query)
  includeTotalCount?: boolean;
}

/**
 * Paginated query result
 */
export interface PaginatedResult<T> {
  items: T[];
  pagination: {
    limit: number;
    hasMore: boolean;
    nextCursor?: string;
    totalCount?: number;
  };
}

/**
 * Cursor structure for pagination
 */
interface Cursor {
  timestamp: string; // ISO 8601 timestamp
  id: string; // Email ID for tie-breaking
}

/**
 * Connection pool using standard db-utils
 */
let pool: Pool | null = null;

/**
 * Detect if running in container environment (same logic as connect-as.sh)
 */
function detectPostgresHost(): string {
  const envHost = process.env.POSTGRES_HOST;
  if (envHost && envHost !== 'localhost') {
    return envHost;
  }

  // Check if running in container (/.dockerenv or /run/.containerenv exists)
  if (fs.existsSync('/.dockerenv') || fs.existsSync('/run/.containerenv')) {
    return 'pg-n8n-local';
  }

  return 'localhost';
}

function getPool(): Pool {
  if (!pool) {
    // Load environment from project-init/.env if not already set
    if (!process.env.PROJECT_DB_NAME) {
      dotenv.config({ path: path.resolve(__dirname, '../../../../database/project-init/.env') });
    }

    const host = detectPostgresHost();

    // Use db-utils createPool with container-aware host detection
    pool = createPool({
      host,
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 2000,
    });
  }
  return pool;
}

interface DatabaseRow {
  gmail_id: string;
  gmail_thread_id: string;
  label_ids: string[];
  subject?: string;
  sent_at?: Date;
  message_id_hdr?: string;
  from_simple: Record<string, unknown> | string;
  to_addrs: Record<string, unknown>[] | string;
  reply_to_addrs?: Record<string, unknown>[] | string;
  headers: Record<string, unknown>[] | string;
  body_text?: string;
  body_html?: string;
  raw: Record<string, unknown> | string;
  size_estimate?: number;
  session_id?: number;
  completed_at?: Date;
}

/**
 * Map database row to EmailMessage interface
 */
function mapRowToEmailMessage(row: DatabaseRow): EmailMessage {
  // Parse date safely
  const sentAt = row.sent_at ? new Date(row.sent_at) : new Date();

  // Parse from address
  const fromSimple = typeof row.from_simple === 'string' ? JSON.parse(row.from_simple) : row.from_simple;
  const from: EmailAddress = {
    email: (fromSimple.address as string) || (fromSimple.email as string) || '',
    name: fromSimple.name as string | undefined,
    raw: ((fromSimple.raw || fromSimple.address || fromSimple.email) as string) || '',
  };

  // Parse to addresses
  const toAddrs = typeof row.to_addrs === 'string' ? JSON.parse(row.to_addrs) : row.to_addrs;
  const to: EmailAddress[] = (Array.isArray(toAddrs) ? toAddrs : []).map((addr: Record<string, unknown>) => ({
    email: (addr.address as string) || (addr.email as string) || '',
    name: addr.name as string | undefined,
    raw: ((addr.raw || addr.address || addr.email) as string) || '',
  }));

  // Parse headers
  const headers = typeof row.headers === 'string' ? JSON.parse(row.headers) : row.headers;
  const headerArray: EmailHeader[] = Array.isArray(headers)
    ? headers.map((h: Record<string, unknown>) => ({
        name: (h.name as string) || '',
        value: (h.value as string) || '',
      }))
    : [];

  // Parse raw Gmail payload
  const rawPayload = typeof row.raw === 'string' ? JSON.parse(row.raw) : row.raw;

  // Parse reply-to if exists
  let replyTo: EmailAddress[] | undefined;
  if (row.reply_to_addrs) {
    const replyToAddrs = typeof row.reply_to_addrs === 'string' ? JSON.parse(row.reply_to_addrs) : row.reply_to_addrs;
    replyTo = (Array.isArray(replyToAddrs) ? replyToAddrs : []).map((addr: Record<string, unknown>) => ({
      email: (addr.address as string) || (addr.email as string) || '',
      name: addr.name as string | undefined,
      raw: ((addr.raw || addr.address || addr.email) as string) || '',
    }));
  }

  // Type guard for payload - Gmail API response structure
  const payload = rawPayload as
    | { payload?: { mimeType?: string; body?: unknown; parts?: unknown }; snippet?: string }
    | undefined;

  return {
    id: row.gmail_id,
    threadId: row.gmail_thread_id,
    gmailLabels: Array.isArray(row.label_ids) ? row.label_ids : [],
    payload: {
      mimeType: (payload?.payload?.mimeType as string) || 'text/plain',
      headers: headerArray,
      body: payload?.payload?.body as MessagePartBody | undefined,
      parts: payload?.payload?.parts as MessagePart[] | undefined,
    },
    subject: row.subject || '',
    from,
    to,
    replyTo,
    date: sentAt,
    messageId: row.message_id_hdr,
    bodyPlain: row.body_text,
    bodyHtml: row.body_html,
    snippet: payload?.snippet as string | undefined,
    sizeEstimate: row.size_estimate,
    isProcessed: !!row.session_id, // Has classification session
    processingSessionId: row.session_id ? String(row.session_id) : undefined,
    processedAt: row.completed_at ? new Date(row.completed_at) : undefined,
    processingPriority: 0, // Default priority for testing
  };
}

/**
 * Fetch emails within specified date range
 *
 * @param startDate - Start of date range (inclusive)
 * @param endDate - End of date range (inclusive)
 * @param limit - Maximum number of emails to return (default: 100)
 * @returns Array of EmailMessage objects
 */
export async function fetchEmailsByDateRange(
  startDate: Date,
  endDate: Date,
  limit: number = 100
): Promise<EmailMessage[]> {
  // Validate date range
  if (startDate > endDate) {
    throw new Error('Invalid date range: start date must be before end date');
  }

  const pool = getPool();

  const query = `
    SELECT
      gm.gmail_id,
      gm.gmail_thread_id,
      gm.label_ids,
      gm.subject,
      gm.sent_at,
      gm.message_id_hdr,
      gm.from_simple,
      gm.to_addrs,
      gm.reply_to_addrs,
      gm.headers,
      gm.body_text,
      gm.body_html,
      gm.raw,
      gm.size_estimate,
      cs.session_id,
      cs.completed_at
    FROM email.gmail_message gm
    LEFT JOIN LATERAL (
      SELECT session_id, completed_at
      FROM email.classification_session
      WHERE gmail_id = gm.gmail_id
      ORDER BY started_at DESC
      LIMIT 1
    ) cs ON true
    WHERE gm.sent_at >= $1 AND gm.sent_at <= $2
    ORDER BY gm.sent_at DESC
    LIMIT $3
  `;

  try {
    const result = await pool.query(query, [startDate, endDate, limit]);
    return result.rows.map(mapRowToEmailMessage);
  } catch (error) {
    throw new Error(`Failed to fetch emails by date range: ${(error as Error).message}`);
  }
}

/**
 * Fetch single email by Gmail message ID
 *
 * @param messageId - Gmail message ID
 * @returns EmailMessage object
 * @throws Error if message not found or messageId is invalid
 */
export async function fetchEmailById(messageId: string): Promise<EmailMessage> {
  // Validate input
  if (!messageId || typeof messageId !== 'string' || messageId.trim() === '') {
    throw new Error('Message ID is required and must be a non-empty string');
  }

  const pool = getPool();

  const query = `
    SELECT
      gm.gmail_id,
      gm.gmail_thread_id,
      gm.label_ids,
      gm.subject,
      gm.sent_at,
      gm.message_id_hdr,
      gm.from_simple,
      gm.to_addrs,
      gm.reply_to_addrs,
      gm.headers,
      gm.body_text,
      gm.body_html,
      gm.raw,
      gm.size_estimate,
      cs.session_id,
      cs.completed_at
    FROM email.gmail_message gm
    LEFT JOIN LATERAL (
      SELECT session_id, completed_at
      FROM email.classification_session
      WHERE gmail_id = gm.gmail_id
      ORDER BY started_at DESC
      LIMIT 1
    ) cs ON true
    WHERE gm.gmail_id = $1
  `;

  try {
    const result = await pool.query(query, [messageId]);

    if (result.rows.length === 0) {
      throw new Error(`Email with message ID "${messageId}" not found in database`);
    }

    return mapRowToEmailMessage(result.rows[0]);
  } catch (error) {
    if ((error as Error).message.includes('not found')) {
      throw error;
    }
    throw new Error(`Failed to fetch email by ID: ${(error as Error).message}`);
  }
}

/**
 * Fetch emails without classification_session records
 *
 * @param limit - Maximum number of emails to return (default: 100)
 * @returns Array of unclassified EmailMessage objects
 */
export async function fetchUnclassifiedEmails(limit: number = 100): Promise<EmailMessage[]> {
  const pool = getPool();

  const query = `
    SELECT
      gm.gmail_id,
      gm.gmail_thread_id,
      gm.label_ids,
      gm.subject,
      gm.sent_at,
      gm.message_id_hdr,
      gm.from_simple,
      gm.to_addrs,
      gm.reply_to_addrs,
      gm.headers,
      gm.body_text,
      gm.body_html,
      gm.raw,
      gm.size_estimate,
      NULL as session_id,
      NULL as completed_at
    FROM email.gmail_message gm
    LEFT JOIN email.classification_session cs ON gm.gmail_id = cs.gmail_id
    WHERE cs.session_id IS NULL
    ORDER BY gm.sent_at DESC
    LIMIT $1
  `;

  try {
    const result = await pool.query(query, [limit]);
    return result.rows.map(mapRowToEmailMessage);
  } catch (error) {
    throw new Error(`Failed to fetch unclassified emails: ${(error as Error).message}`);
  }
}

/**
 * Encode cursor for pagination
 */
function encodeCursor(cursor: Cursor): string {
  const json = JSON.stringify(cursor);
  return Buffer.from(json).toString('base64');
}

/**
 * Decode cursor for pagination
 */
function decodeCursor(cursorStr: string): Cursor {
  try {
    const json = Buffer.from(cursorStr, 'base64').toString('utf-8');
    const cursor = JSON.parse(json) as Cursor;

    // Validate cursor structure
    if (!cursor.timestamp || !cursor.id) {
      throw new Error('Invalid cursor structure');
    }

    // Validate timestamp format
    if (isNaN(new Date(cursor.timestamp).getTime())) {
      throw new Error('Invalid cursor timestamp');
    }

    return cursor;
  } catch (error) {
    throw new Error(`Invalid cursor format: ${(error as Error).message}`);
  }
}

/**
 * Build WHERE clause from criteria
 */
function buildWhereClause(
  criteria: EmailQueryCriteria,
  paramOffset: number = 0
): { clause: string; params: unknown[] } {
  const conditions: string[] = [];
  const params: unknown[] = [];
  let paramIndex = paramOffset + 1;

  // Subject filter
  if (criteria.subject) {
    conditions.push(`gm.subject ILIKE $${paramIndex}`);
    params.push(`%${criteria.subject}%`);
    paramIndex++;
  }

  // From filter
  if (criteria.from) {
    conditions.push(`(gm.from_simple::text ILIKE $${paramIndex})`);
    params.push(`%${criteria.from}%`);
    paramIndex++;
  }

  // Body contains filter
  if (criteria.bodyContains) {
    conditions.push(`(gm.body_text ILIKE $${paramIndex} OR gm.body_html ILIKE $${paramIndex})`);
    params.push(`%${criteria.bodyContains}%`);
    paramIndex++;
  }

  // Date range filter
  if (criteria.dateRange) {
    conditions.push(`gm.sent_at >= $${paramIndex}`);
    params.push(criteria.dateRange.start);
    paramIndex++;

    conditions.push(`gm.sent_at <= $${paramIndex}`);
    params.push(criteria.dateRange.end);
    paramIndex++;
  }

  // Gmail labels filter (OR logic)
  if (criteria.gmailLabels && criteria.gmailLabels.length > 0) {
    conditions.push(`gm.label_ids && $${paramIndex}::text[]`);
    params.push(criteria.gmailLabels);
    paramIndex++;
  }

  // Processing status filter
  if (criteria.isProcessed !== undefined) {
    if (criteria.isProcessed) {
      conditions.push('cs.session_id IS NOT NULL');
    } else {
      conditions.push('cs.session_id IS NULL');
    }
  }

  // Primary category filter (requires JOIN with session_category)
  if (criteria.primaryCategory) {
    conditions.push(`sc.category_code = $${paramIndex}`);
    params.push(criteria.primaryCategory);
    paramIndex++;
    conditions.push('sc.label_type = 0'); // 0 = PRIMARY
  }

  // Minimum confidence filter (requires JOIN with classification_session)
  if (criteria.minConfidence !== undefined) {
    conditions.push(`cs.confidence >= $${paramIndex}`);
    params.push(criteria.minConfidence);
    paramIndex++;
  }

  // Urgency filter (requires JOIN with detected_attribute)
  if (criteria.urgency) {
    conditions.push(`da.attribute_name = 'urgency'`);
    conditions.push(`da.attribute_value = $${paramIndex}`);
    params.push(criteria.urgency);
    paramIndex++;
  }

  const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
  return { clause: whereClause, params };
}

/**
 * Build FROM clause with necessary JOINs based on criteria
 */
function buildFromClause(criteria: EmailQueryCriteria, pagination?: PaginationOptions): string {
  let fromClause = 'FROM email.gmail_message gm';

  // Always LEFT JOIN classification_session for processing status
  fromClause += `
    LEFT JOIN LATERAL (
      SELECT session_id, completed_at, final_confidence as confidence
      FROM email.classification_session
      WHERE gmail_id = gm.gmail_id
      ORDER BY started_at DESC
      LIMIT 1
    ) cs ON true`;

  // JOIN session_categories if filtering by category
  if (criteria.primaryCategory) {
    fromClause += `
    LEFT JOIN email.session_categories sc ON cs.session_id = sc.session_id`;
  }

  // JOIN detected_attribute if filtering by urgency
  if (criteria.urgency) {
    fromClause += `
    LEFT JOIN email.detected_attribute da ON cs.session_id = da.session_id`;
  }

  // JOIN for confidence-based sorting
  if (pagination?.sortBy === 'confidence') {
    // Already have cs.confidence from classification_session JOIN
  }

  return fromClause;
}

/**
 * Build ORDER BY clause
 */
function buildOrderByClause(pagination?: PaginationOptions): string {
  const sortBy = pagination?.sortBy || 'date';
  const sortOrder = pagination?.sortOrder || 'desc';

  if (sortBy === 'confidence') {
    return `ORDER BY cs.confidence ${sortOrder.toUpperCase()}, gm.sent_at DESC`;
  }

  // Default: sort by date
  return `ORDER BY gm.sent_at ${sortOrder.toUpperCase()}`;
}

/**
 * Validate criteria and pagination options
 */
function validateCriteriaAndPagination(criteria: EmailQueryCriteria, pagination?: PaginationOptions): void {
  // Validate date range
  if (criteria.dateRange) {
    if (criteria.dateRange.start > criteria.dateRange.end) {
      throw new Error('Invalid date range: start date must be before end date');
    }
  }

  // Validate confidence range
  if (criteria.minConfidence !== undefined) {
    if (criteria.minConfidence < 0 || criteria.minConfidence > 1) {
      throw new Error('Invalid confidence: must be between 0.0 and 1.0');
    }
  }

  // Validate pagination limit
  if (pagination?.limit !== undefined) {
    if (pagination.limit < 0) {
      throw new Error('Invalid limit: must be non-negative');
    }
    if (pagination.limit > 1000) {
      throw new Error('Limit exceeds maximum allowed value of 1000');
    }
  }
}

/**
 * Fetch emails with criteria-based selection and pagination (T048)
 *
 * @param criteria - Query criteria for filtering
 * @param pagination - Pagination options (limit, cursor, sort)
 * @returns Paginated result with email messages
 */
export async function fetchEmailsByCriteria(
  criteria: EmailQueryCriteria,
  pagination?: PaginationOptions
): Promise<PaginatedResult<EmailMessage>> {
  // Validate inputs
  validateCriteriaAndPagination(criteria, pagination);

  const pool = getPool();

  // Pagination defaults
  const limit = pagination?.limit || 50;
  const includeTotalCount = pagination?.includeTotalCount || false;

  // Decode cursor if provided
  let cursorData: Cursor | null = null;
  if (pagination?.cursor) {
    cursorData = decodeCursor(pagination.cursor);
  }

  // Build query components
  const { clause: whereClause, params } = buildWhereClause(criteria);
  const fromClause = buildFromClause(criteria, pagination);
  const orderByClause = buildOrderByClause(pagination);

  // Add cursor conditions to WHERE clause
  let cursorCondition = '';
  let cursorParams: unknown[] = [];
  if (cursorData) {
    const cursorParamIndex = params.length + 1;
    const sortOrder = pagination?.sortOrder || 'desc';

    if (sortOrder === 'desc') {
      cursorCondition = `AND (gm.sent_at < $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id < $${cursorParamIndex + 1}))`;
    } else {
      cursorCondition = `AND (gm.sent_at > $${cursorParamIndex} OR (gm.sent_at = $${cursorParamIndex} AND gm.gmail_id > $${cursorParamIndex + 1}))`;
    }
    cursorParams = [cursorData.timestamp, cursorData.id];
  }

  // Construct main query (fetch limit + 1 to determine hasMore)
  const query = `
    SELECT
      gm.gmail_id,
      gm.gmail_thread_id,
      gm.label_ids,
      gm.subject,
      gm.sent_at,
      gm.message_id_hdr,
      gm.from_simple,
      gm.to_addrs,
      gm.reply_to_addrs,
      gm.headers,
      gm.body_text,
      gm.body_html,
      gm.raw,
      gm.size_estimate,
      cs.session_id,
      cs.completed_at
    ${fromClause}
    ${whereClause} ${cursorCondition}
    ${orderByClause}
    LIMIT $${params.length + cursorParams.length + 1}
  `;

  const queryParams = [...params, ...cursorParams, limit + 1];

  try {
    // Execute main query
    const result = await pool.query(query, queryParams);

    // Determine hasMore and prepare items
    const hasMore = result.rows.length > limit;
    const items = result.rows.slice(0, limit).map(mapRowToEmailMessage);

    // Generate nextCursor if hasMore
    let nextCursor: string | undefined;
    if (hasMore && items.length > 0) {
      const lastItem = items[items.length - 1];
      nextCursor = encodeCursor({
        timestamp: lastItem.date.toISOString(),
        id: lastItem.id,
      });
    }

    // Fetch total count if requested (separate query for performance)
    let totalCount: number | undefined;
    if (includeTotalCount) {
      const countQuery = `
        SELECT COUNT(*) as count
        ${fromClause}
        ${whereClause}
      `;

      const countResult = await pool.query(countQuery, params);
      totalCount = parseInt(countResult.rows[0].count, 10);
    }

    return {
      items,
      pagination: {
        limit,
        hasMore,
        nextCursor,
        totalCount,
      },
    };
  } catch (error) {
    throw new Error(`Failed to fetch emails by criteria: ${(error as Error).message}`);
  }
}

/**
 * Close the connection pool (for testing cleanup)
 */
export async function closePool(): Promise<void> {
  if (pool) {
    await pool.end();
    pool = null;
  }
}

